/**
 * Sliding Window Rate Limiter for Express.js
 *
 * This is a TRUE sliding window: every request timestamp is stored per client,
 * and on each request we evict timestamps older than `windowMs` relative to
 * *now*. The window therefore slides continuously with the clock — there is no
 * fixed bucket that resets at a fixed interval. A burst at the edge of an old
 * window cannot "double up" against a burst at the start of a new one, which is
 * the classic weakness of fixed-window limiters.
 *
 * NOTE on `req.ip` behind proxies:
 *   When your app sits behind a reverse proxy / load balancer (Nginx, ELB,
 *   Cloudflare, etc.), `req.ip` will be the proxy's address unless Express is
 *   told to trust the `X-Forwarded-For` header. Enable it with:
 *
 *       app.set('trust proxy', 1);   // trust the first hop (your nginx)
 *
 *   Without this, every client behind the proxy shares one IP and gets limited
 *   collectively. Set the trust level to match exactly how many proxies you
 *   control — trusting too liberally lets clients spoof X-Forwarded-For and
 *   evade or poison the limiter. You can also override key extraction via the
 *   `keyGenerator` option below.
 *
 * @param {Object}   [options]
 * @param {number}   [options.windowMs=60000]     Window size in milliseconds.
 * @param {number}   [options.maxRequests=100]    Max requests allowed per window.
 * @param {Function} [options.keyGenerator]       (req) => string client key.
 *                                                 Defaults to req.ip.
 * @returns {Function} Express middleware. The middleware also exposes a
 *                      `.close()` method to stop the cleanup timer.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> — sorted-ascending arrays of request timestamps.
  const hits = new Map();

  /**
   * Drop all timestamps older than the sliding window cutoff.
   * Timestamps are appended in chronological order, so the array stays sorted
   * and we only need to find the first index that's still inside the window.
   *
   * @param {number[]} timestamps
   * @param {number}   cutoff  Anything at or before this is evicted.
   * @returns {number[]} A (possibly new) array containing only fresh timestamps.
   */
  function evictOld(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  // --- Periodic cleanup -----------------------------------------------------
  // Removes whole entries for clients that have had zero requests within the
  // last windowMs, so the Map doesn't grow unbounded with one-off IPs.
  const cleanupIntervalMs = 60000;
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      // The last timestamp is the most recent. If even that is expired, the
      // whole entry is stale and can be dropped.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        hits.delete(key);
      }
    }
  }, cleanupIntervalMs);

  // unref() lets the Node.js process exit naturally even if the timer is still
  // pending — the timer alone won't keep the event loop alive.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // --- Middleware -----------------------------------------------------------
  function middleware(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;
    const key = keyGenerator(req);

    const existing = hits.get(key) || [];
    const fresh = evictOld(existing, cutoff);

    if (fresh.length >= maxRequests) {
      // Over the limit — reject WITHOUT recording this request.
      // The window frees a slot once the oldest in-window timestamp expires.
      const oldest = fresh[0];
      const msUntilReset = oldest + windowMs - now;
      const retryAfterSec = Math.max(1, Math.ceil(msUntilReset / 1000));
      const resetEpochSec = Math.ceil((now + msUntilReset) / 1000);

      // Persist the evicted array so memory doesn't accumulate on rejected reqs.
      hits.set(key, fresh);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', resetEpochSec);
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it.
    fresh.push(now);
    hits.set(key, fresh);

    const remaining = maxRequests - fresh.length;
    // Reset = when the oldest in-window request expires, i.e. when capacity
    // first increases again.
    const resetEpochSec = Math.ceil((fresh[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', resetEpochSec);

    next();
  }

  /**
   * Stop the background cleanup timer. Call this on graceful shutdown (or in
   * tests) so the interval doesn't keep the process alive. Safe to call twice.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

