      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // Request is allowed: record the current timestamp
    timestamps.push(now);
    requests.set(ip, timestamps);

    // === Rate limit response headers (only set on successful/allowed requests) ===
    res.set('X-RateLimit-Limit', String(maxRequests));

    // Remaining quota after this request has been counted.
    const remaining = maxRequests - timestamps.length;
    res.set('X-RateLimit-Remaining', String(remaining));

    // X-RateLimit-Reset: Unix epoch seconds when the oldest request in the
    // current window will expire (i.e. the moment the count will drop by one).
    // This is the semantically correct value for a sliding window.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);
    res.set('X-RateLimit-Reset', String(resetEpochSec));

    next();
  }

  // Expose the cleanup method directly on the middleware function.
  // Usage: const limiter = createRateLimiter();  app.use(limiter);  ...  limiter.close();
  rateLimitMiddleware.close = close;

  // Exposed for testing / introspection only (not part of public API)
  rateLimitMiddleware._store = requests;

  return rateLimitMiddleware;
}

